#include<bits/stdc++.h>
using namespace std;
int n;
const int N=50010;
struct segment_tree
{
    struct node
    {
        int lson,rson;
        int sum;
    }a[60000010];
    int cnt,root[N],q1[N],q2[N],val[N],flag[N],tot1,tot2;
    segment_tree():cnt(0){}
    void pushup(int x)
    {
        a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    }
    int query(int l,int r,int k)
    {
        if(l==r)
        {
            return 0;
        }
        int mid=(l+r)>>1;
        if(k<=mid)
        {
            for(int i=1;i<=tot1;i++)
            {
                q1[i]=a[q1[i]].lson;
            }
            for(int i=1;i<=tot2;i++)
            {
                q2[i]=a[q2[i]].lson;
            }
            return query(l,mid,k);
        }
        else
        {
            int sum=0;
            for(int i=1;i<=tot1;i++)
            {
                sum+=a[a[q1[i]].lson].sum;
                q1[i]=a[q1[i]].rson;
            }
            for(int i=1;i<=tot2;i++)
            {
                sum-=a[a[q2[i]].lson].sum;
                q2[i]=a[q2[i]].rson;
            }
            return query(mid+1,r,k)+sum;
        }
    }
    int find(int l,int r,int k)
    {
        if(l==r)
        {
            return l;
        }
        int mid=(l+r)>>1,sum=0;
        for(int i=1;i<=tot1;i++)
        {
            sum+=a[a[q1[i]].lson].sum;
        }
        for(int i=1;i<=tot2;i++)
        {
            sum-=a[a[q2[i]].lson].sum;
        }
        if(k<=sum)
        {
            for(int i=1;i<=tot1;i++)
            {
                q1[i]=a[q1[i]].lson;
            }
            for(int i=1;i<=tot2;i++)
            {
                q2[i]=a[q2[i]].lson;
            }
            return find(l,mid,k);
        }
        else
        {
            for(int i=1;i<=tot1;i++)
            {
                q1[i]=a[q1[i]].rson;
            }
            for(int i=1;i<=tot2;i++)
            {
                q2[i]=a[q2[i]].rson;
            }
            return find(mid+1,r,k-sum);
        }
    }
    void add(int &x,int l,int r,int p,int v)
    {
        if(x==0)
        {
            x=++cnt;
        }
        if(l==r)
        {
            a[x].sum+=v;
            return;
        }
        int mid=(l+r)>>1;
        if(p<=mid)
        {
            add(a[x].lson,l,mid,p,v);
        }
        else
        {
            add(a[x].rson,mid+1,r,p,v);
        }
        pushup(x);
    }
    int lowbit(int x)
    {
        return x&-x;
    }
    void update(int x,int v)
    {
        if(flag[x])
        {
            for(int i=x;i<=n;i+=lowbit(i))
            {
                add(root[i],0,1e8+2,val[x],-1);
            }
        }
        flag[x]=1;
        val[x]=v;
        for(int i=x;i<=n;i+=lowbit(i))
        {
            add(root[i],0,1e8+2,val[x],1);
        }
    }
    int getrnk(int l,int r,int k)
    {
        tot1=tot2=0;
        for(int i=r;i>=1;i-=lowbit(i))
        {
            q1[++tot1]=root[i];
        }
        for(int i=l-1;i>=1;i-=lowbit(i))
        {
            q2[++tot2]=root[i];
        }
        return query(0,1e8+2,k)+1;
    }
    int getkth(int l,int r,int k)
    {
        tot1=tot2=0;
        for(int i=r;i>=1;i-=lowbit(i))
        {
            q1[++tot1]=root[i];
        }
        for(int i=l-1;i>=1;i-=lowbit(i))
        {
            q2[++tot2]=root[i];
        }
        return find(0,1e8+2,k);
    }
    int getpre(int l,int r,int x)
    {
        int tmp=getrnk(l,r,x);
        if(tmp==1)
        {
            return -INT_MAX;
        }
        return getkth(l,r,tmp-1);
    }
    int getnxt(int l,int r,int x)
    {
        int tmp=getrnk(l,r,x+1);
        if(tmp>r-l+1)
        {
            return INT_MAX;
        }
        return getkth(l,r,tmp);
    }
}t;
int main()
{
    int m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        t.update(i,x);
    }
    while(m--)
    {
        int op,l,r,pos,k;
        scanf("%d",&op);
        if(op==3)
        {
            scanf("%d%d",&pos,&k);
            t.update(pos,k);
            continue;
        }
        scanf("%d%d%d",&l,&r,&k);
        if(op==1)
        {
            printf("%d\n",t.getrnk(l,r,k));
        }
        else if(op==2)
        {
            printf("%d\n",t.getkth(l,r,k));
        }
        else if(op==4)
        {
            printf("%d\n",t.getpre(l,r,k));
        }
        else
        {
            printf("%d\n",t.getnxt(l,r,k));
        }
    }
    return 0;
}
